/**
 * Module dependencies
 */
const country = require('./country');

/**
 * Expose country data middleware
 * Adds current country data as a req.country object.
 * @type {import('express').RequestHandler}
 */
const countryConfigMiddleware = (req, res, next) => {
  const countryId = req.platform?.countryId;

  req.country = countryId ? country(countryId) : undefined;

  next();
};

module.exports = countryConfigMiddleware;
